CREATE TABLE IF NOT EXISTS corrections (id TEXT PRIMARY KEY, report_type TEXT NOT NULL, entity_type TEXT NOT NULL, entity_id TEXT NOT NULL, explanation TEXT NOT NULL, evidence_url TEXT, reporter_email_ciphertext TEXT, status TEXT NOT NULL DEFAULT 'RECEIVED', risk_class TEXT NOT NULL, score_impact_json TEXT, created_at TEXT NOT NULL, closed_at TEXT, retention_delete_at TEXT);
CREATE TABLE IF NOT EXISTS correction_events (id TEXT PRIMARY KEY, correction_id TEXT NOT NULL REFERENCES corrections(id), event_type TEXT NOT NULL, actor TEXT NOT NULL, details_json TEXT NOT NULL, created_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS city_expansions (id TEXT PRIMARY KEY, city TEXT NOT NULL, state TEXT NOT NULL, status TEXT NOT NULL, source_manifest_json TEXT NOT NULL DEFAULT '[]', field_map_json TEXT NOT NULL DEFAULT '{}', hard_gates_json TEXT NOT NULL DEFAULT '{}', created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS admin_sessions (id TEXT PRIMARY KEY, token_hash TEXT NOT NULL UNIQUE, created_at TEXT NOT NULL, expires_at TEXT NOT NULL, revoked_at TEXT);
CREATE TABLE IF NOT EXISTS emergency_state (id TEXT PRIMARY KEY, is_stopped INTEGER NOT NULL DEFAULT 0, reason TEXT, updated_at TEXT NOT NULL, updated_by TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS election_records (id TEXT PRIMARY KEY, judge_id TEXT REFERENCES judges(id), election_year INTEGER NOT NULL, election_date TEXT, ballot_status TEXT NOT NULL, source_id TEXT REFERENCES sources(id), last_verified_at TEXT);
CREATE TABLE IF NOT EXISTS score_change_events (id TEXT PRIMARY KEY, judge_id TEXT REFERENCES judges(id), old_score REAL, new_score REAL, trigger TEXT NOT NULL, methodology_version TEXT NOT NULL, public_explanation TEXT NOT NULL, created_at TEXT NOT NULL);
